/**
 * RtcTorrent - WebRTC-enabled BitTorrent client library
 * This library enables WebRTC-based peer-to-peer connections for BitTorrent downloads
 * in browsers and Node.js environments.
 */

class RtcTorrent {
    constructor(options = {}) {
        this.options = {
            trackerUrl: options.trackerUrl || '',
            announceInterval: options.announceInterval || 30000, // 30 seconds
            rtcInterval: options.rtcInterval || 10000,           // 10 seconds for RTC
            maxPeers: options.maxPeers || 50,
            iceServers: options.iceServers || [
                { urls: 'stun:stun.l.google.com:19302' },
                { urls: 'stun:stun1.l.google.com:19302' }
            ],
            ...options
        };

        this.torrents = new Map();
        this.connections = new Map();
        this.announcer = null;
        this.webRtcManager = null;
        this.bencoder = null; // Will initialize when needed

        // Detect environment (browser vs Node.js)
        this.isBrowser = typeof window !== 'undefined';
        this.isFileApiAvailable = this.isBrowser && window.File && window.FileReader && window.Blob;

        // For Node.js, try to import filesystem modules
        if (!this.isBrowser) {
            // Don't assign to this.fs in constructor as webpack will transform these
            // Instead, define helper functions to get modules when needed
            this.getNodeFs = function() {
                try {
                    return require('fs');
                } catch (e) {
                    // In webpack environment, try to access via global
                    if (typeof global !== 'undefined' && global.require) {
                        return global.require('fs');
                    }
                    return null;
                }
            };

            this.getNodePath = function() {
                try {
                    return require('path');
                } catch (e) {
                    // In webpack environment, try to access via global
                    if (typeof global !== 'undefined' && global.require) {
                        return global.require('path');
                    }
                    return null;
                }
            };
        }
    }

    /**
     * Initialize the bencoder module (for torrent file creation)
     */
    async initBencoder() {
        if (this.bencoder) return this.bencoder;

        if (this.isBrowser) {
            // Dynamically load bencoder in browser
            try {
                this.bencoder = await import('bencode'); // Assuming a bencode library is available
            } catch (e) {
                // Fallback to a minimal bencode implementation
                this.bencoder = this.createMinimalBencoder();
            }
        } else {
            // In Node.js, use the built-in bencode or require a library
            try {
                this.bencoder = require('bencode');
            } catch (e) {
                this.bencoder = this.createMinimalBencoder();
            }
        }

        return this.bencoder;
    }

    /**
     * Create a minimal bencode implementation
     */
    createMinimalBencoder() {
        return {
            encode: (obj) => {
                if (typeof obj === 'string') {
                    return `${obj.length}:${obj}`;
                } else if (typeof obj === 'number') {
                    return `i${obj}e`;
                } else if (Array.isArray(obj)) {
                    let encoded = 'l';
                    for (const item of obj) {
                        encoded += this.encodeValue(item);
                    }
                    encoded += 'e';
                    return encoded;
                } else if (obj !== null && typeof obj === 'object') {
                    let encoded = 'd';
                    const keys = Object.keys(obj).sort();
                    for (const key of keys) {
                        encoded += `${key.length}:${key}${this.encodeValue(obj[key])}`;
                    }
                    encoded += 'e';
                    return encoded;
                }
            },

            encodeValue: (val) => {
                if (typeof val === 'string') {
                    return `${val.length}:${val}`;
                } else if (typeof val === 'number') {
                    return `i${val}e`;
                } else if (Array.isArray(val)) {
                    let encoded = 'l';
                    for (const item of val) {
                        encoded += this.encodeValue(item);
                    }
                    encoded += 'e';
                    return encoded;
                } else if (val !== null && typeof val === 'object') {
                    let encoded = 'd';
                    const keys = Object.keys(val).sort();
                    for (const key of keys) {
                        encoded += `${key.length}:${key}${this.encodeValue(val[key])}`;
                    }
                    encoded += 'e';
                    return encoded;
                }
            }
        };
    }

    /**
     * Create a torrent from files or buffer
     */
    async create(files, options = {}) {
        const bencoder = await this.initBencoder();

        // Calculate torrent info
        let totalSize = 0;
        let fileInfos = [];
        let allFileBuffers = [];

        if (Array.isArray(files)) {
            for (const file of files) {
                if (this.isBrowser && this.isFileApiAvailable) {
                    // Browser File API
                    totalSize += file.size || 0;
                    fileInfos.push({
                        length: file.size,
                        path: [file.name || 'file']
                    });

                    // Read file content as ArrayBuffer
                    if (file.arrayBuffer) {
                        const arrayBuffer = await file.arrayBuffer();
                        allFileBuffers.push(Buffer.from(arrayBuffer));
                    }
                } else if (!this.isBrowser && this.getNodeFs && this.getNodePath) {
                    // Node.js file system
                    const fs = this.getNodeFs();
                    const pathModule = this.getNodePath();

                    if (!fs || !pathModule) {
                        // If fs is not available, skip file processing
                        continue;
                    }

                    let filePath, fileName;

                    if (typeof file === 'string') {
                        filePath = file;
                        // Extract filename without using path module to avoid webpack issues
                        fileName = pathModule.basename(filePath);
                    } else if (file && typeof file === 'object' && file.path) {
                        filePath = file.path;
                        fileName = file.name || pathModule.basename(filePath);
                    } else {
                        // Skip if file format is invalid
                        continue;
                    }

                    const stats = fs.statSync(filePath);
                    totalSize += stats.size;
                    fileInfos.push({
                        length: stats.size,
                        path: [fileName]
                    });

                    // Read file content
                    const fileBuffer = fs.readFileSync(filePath);
                    allFileBuffers.push(fileBuffer);
                } else {
                    // Generic object
                    totalSize += file.size || 0;
                    fileInfos.push({
                        length: file.size,
                        path: [file.name || 'file']
                    });
                }
            }
        } else if (typeof files === 'object') {
            for (const [name, file] of Object.entries(files)) {
                if (this.isBrowser && this.isFileApiAvailable && file instanceof File) {
                    totalSize += file.size;
                    fileInfos.push({
                        length: file.size,
                        path: [file.name]
                    });

                    // Read file content as ArrayBuffer
                    if (file.arrayBuffer) {
                        const arrayBuffer = await file.arrayBuffer();
                        allFileBuffers.push(Buffer.from(arrayBuffer));
                    }
                } else if (!this.isBrowser && this.getNodeFs && this.getNodePath && typeof file === 'string') {
                    const fs = this.getNodeFs();
                    const pathModule = this.getNodePath();

                    if (!fs || !pathModule) {
                        // If fs is not available, skip file processing
                        continue;
                    }

                    const stats = fs.statSync(file);
                    totalSize += stats.size;
                    fileInfos.push({
                        length: stats.size,
                        path: [pathModule.basename(file)]
                    });

                    // Read file content
                    const fileBuffer = fs.readFileSync(file);
                    allFileBuffers.push(fileBuffer);
                } else {
                    totalSize += file.size || 0;
                    fileInfos.push({
                        length: file.size,
                        path: [file.name || name]
                    });
                }
            }
        }

        // Determine piece length based on total size (standard algorithm)
        let pieceLength = 256 * 1024; // 256KB default
        if (totalSize > 8 * 1024 * 1024) pieceLength = 512 * 1024; // 512KB for larger files
        if (totalSize > 32 * 1024 * 1024) pieceLength = 1024 * 1024; // 1MB for large files

        // Combine all file buffers into one if there are multiple files
        let combinedBuffer;
        if (allFileBuffers.length > 0) {
            combinedBuffer = Buffer.concat(allFileBuffers);
        } else {
            // Fallback: create a dummy buffer if no real files were read
            combinedBuffer = Buffer.alloc(totalSize);
        }

        // Calculate number of pieces
        const numPieces = Math.ceil(totalSize / pieceLength);

        // Create proper pieces array - should be concatenation of all SHA-1 hashes of actual pieces
        const piecesArray = new Uint8Array(numPieces * 20);

        // Calculate actual SHA-1 hashes for each piece
        for (let i = 0; i < numPieces; i++) {
            const start = i * pieceLength;
            const end = Math.min(start + pieceLength, combinedBuffer.length);
            const piece = combinedBuffer.slice(start, end);

            // Calculate SHA-1 hash for this piece
            const pieceHash = await this.sha1Buffer(piece);

            // Copy the hash to the appropriate position in piecesArray
            for (let j = 0; j < 20; j++) {
                piecesArray[i * 20 + j] = pieceHash[j];
            }
        }

        // Prepare the torrent info dictionary
        const info = {
            name: options.name || 'UnnamedTorrent',
            'piece length': pieceLength,  // Use 'piece length' instead of 'piece_length' (this is the correct key)
            pieces: Buffer.from(piecesArray), // Convert to Buffer for Node.js compatibility
            length: totalSize
        };

        // Add files array if multiple files
        if (fileInfos.length > 1) {
            info.files = fileInfos;
            delete info.length; // Remove length if multiple files
        } else if (fileInfos.length === 1) {
            info.length = fileInfos[0].length;
        }

        const torrent = {
            info: info,
            announce: this.options.trackerUrl,
            'creation date': Math.floor(Date.now() / 1000),
            'created by': 'RtcTorrent v1.0.0'
        };

        // Calculate info hash (SHA-1 of bencoded info dict)
        const bencodedInfo = bencoder.encode(torrent.info);
        const infoHash = this.sha1Hex(bencodedInfo);

        // Store the original file data so we can serve it when seeding
        torrent._originalFiles = allFileBuffers;
        torrent._pieceLength = pieceLength;

        return {
            torrent: torrent,
            magnetUri: this.createMagnetURI(torrent, infoHash),
            infoHash: infoHash,
            encodedTorrent: bencoder.encode(torrent)
        };
    }

    /**
     * Calculate SHA-1 hash in hexadecimal format
     */
    sha1Hex(data) {
        // Simplified implementation - in production, use a proper crypto library
        if (this.isBrowser) {
            // Use Web Crypto API
            return this.sha1Browser(data);
        } else {
            // Use Node.js crypto
            try {
                const crypto = require('crypto');
                return crypto.createHash('sha1').update(data).digest('hex');
            } catch (e) {
                // Fallback to manual implementation for demo
                return this.simpleHash(data);
            }
        }
    }

    async sha1Browser(data) {
        if (typeof data === 'string') {
            data = new TextEncoder().encode(data);
        }

        const buffer = await crypto.subtle.digest('SHA-1', data);
        const hashArray = Array.from(new Uint8Array(buffer));
        return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
    }

    async sha1Buffer(data) {
        // Use Web Crypto API for browsers or Node.js crypto
        if (this.isBrowser) {
            const buffer = await crypto.subtle.digest('SHA-1', data);
            return new Uint8Array(buffer);
        } else {
            try {
                const crypto = require('crypto');
                return crypto.createHash('sha1').update(data).digest();
            } catch (e) {
                // Fallback to simple implementation for testing
                // In a real scenario, this would return proper SHA-1 digest as Uint8Array
                return new Uint8Array(20).fill(0x42); // Placeholder
            }
        }
    }

    /**
     * Create a magnet URI from torrent data
     */
    createMagnetURI(torrent, infoHash) {
        if (!infoHash) {
            infoHash = this.calculateInfoHash(torrent.info);
        }

        const trackers = Array.isArray(torrent.announce) ? torrent.announce : [torrent.announce];
        const params = [`xt=urn:btih:${infoHash}`];

        if (torrent.info && torrent.info.name) {
            params.push(`dn=${encodeURIComponent(torrent.info.name)}`);
        }

        trackers.forEach(tracker => {
            if (tracker) {
                params.push(`tr=${encodeURIComponent(tracker)}`);
            }
        });

        return `magnet:?${params.join('&')}`;
    }

    /**
     * Calculate info hash from info dictionary
     */
    calculateInfoHash(info) {
        // This is a simplified version - in practice, you'd properly bencode and SHA-1 hash
        const bencoder = this.createMinimalBencoder();
        const bencodedInfo = bencoder.encode(info);
        return this.sha1Hex(bencodedInfo);
    }

    /**
     * Load and start downloading a torrent
     */
    async download(torrentData) {
        let torrent = torrentData;

        // Handle different input formats
        if (typeof torrentData === 'string') {
            if (torrentData.startsWith('magnet:')) {
                torrent = await this.parseMagnet(torrentData);
            } else {
                // Assume it's a URL to a .torrent file
                torrent = await this.fetchTorrentFile(torrentData);
            }
        } else if (torrentData instanceof Uint8Array || Buffer.isBuffer(torrentData)) {
            // Raw torrent file data
            torrent = await this.parseTorrentFile(torrentData);
        }

        const torrentId = torrent.infoHash || this.calculateInfoHash(torrent.info);

        if (this.torrents.has(torrentId)) {
            throw new Error('Torrent already exists');
        }

        const torrentInstance = new Torrent(this, torrent, this.options);
        this.torrents.set(torrentId, torrentInstance);

        return await torrentInstance.start();
    }

    /**
     * Seed a torrent from files or an existing torrent structure
     */
    async seed(torrentData, files = null) {
        let torrent = torrentData;

        // If we're given files, create a new torrent from them
        if (files !== null) {
            const createdTorrent = await this.create(files, { name: torrentData.name || 'SeededTorrent' });
            torrent = createdTorrent.torrent;
        }

        // Handle different input formats for existing torrents
        if (typeof torrentData === 'string') {
            if (torrentData.startsWith('magnet:')) {
                torrent = await this.parseMagnet(torrentData);
            } else {
                // Assume it's a URL to a .torrent file
                torrent = await this.fetchTorrentFile(torrentData);
            }
        } else if (torrentData instanceof Uint8Array || Buffer.isBuffer(torrentData)) {
            // Raw torrent file data
            torrent = await this.parseTorrentFile(torrentData);
        }

        const torrentId = torrent.infoHash || this.calculateInfoHash(torrent.info);

        if (this.torrents.has(torrentId)) {
            throw new Error('Torrent already exists');
        }

        const torrentInstance = new Torrent(this, torrent, this.options);
        this.torrents.set(torrentId, torrentInstance);

        return await torrentInstance.seed();
    }

    /**
     * Parse a .torrent file
     */
    async parseTorrentFile(torrentData) {
        const bencoder = await this.initBencoder();

        try {
            let decoded;
            if (typeof torrentData === 'string') {
                // If it's a Base64 string
                if (/^[A-Za-z0-9+/]*={0,2}$/.test(torrentData)) {
                    const binary = atob(torrentData);
                    const bytes = new Uint8Array(binary.length);
                    for (let i = 0; i < binary.length; i++) {
                        bytes[i] = binary.charCodeAt(i);
                    }
                    decoded = bencoder.decode(Buffer.from(bytes));
                } else {
                    decoded = bencoder.decode(Buffer.from(torrentData, 'utf8'));
                }
            } else if (Buffer.isBuffer(torrentData)) {
                decoded = bencoder.decode(torrentData);
            } else if (torrentData instanceof Uint8Array) {
                decoded = bencoder.decode(Buffer.from(torrentData));
            }

            const infoHash = this.sha1Hex(bencoder.encode(decoded.info));

            return {
                info: decoded.info,
                announce: decoded.announce,
                infoHash: infoHash,
                name: decoded.info?.name || 'Unknown'
            };
        } catch (error) {
            throw new Error(`Failed to parse torrent file: ${error.message}`);
        }
    }

    /**
     * Fetch a .torrent file from a URL
     */
    async fetchTorrentFile(url) {
        const response = await fetch(url);
        if (!response.ok) {
            throw new Error(`Failed to fetch torrent: ${response.statusText}`);
        }

        const arrayBuffer = await response.arrayBuffer();
        return await this.parseTorrentFile(new Uint8Array(arrayBuffer));
    }

    /**
     * Parse magnet URI
     */
    async parseMagnet(magnetUri) {
        try {
            const url = new URL(magnetUri);
            if (url.protocol !== 'magnet:') {
                throw new Error('Invalid magnet URI');
            }

            const params = {};
            for (const [key, value] of url.searchParams) {
                params[key] = value;
            }

            const infoHash = params.xt.replace('urn:btih:', '');

            // Decode hex-encoded info hash if needed
            let decodedInfoHash = infoHash;
            if (infoHash.length === 40 && /^[0-9a-fA-F]+$/.test(infoHash)) {
                // Already hex, use as-is
            } else if (infoHash.startsWith('urn:btih:')) {
                decodedInfoHash = infoHash.replace('urn:btih:', '');
            }

            return {
                infoHash: decodedInfoHash.toLowerCase(),
                announce: params.tr ? (Array.isArray(params.tr) ? params.tr : [params.tr]) : [this.options.trackerUrl],
                name: params.dn ? decodeURIComponent(params.dn) : 'Unknown'
            };
        } catch (error) {
            throw new Error(`Failed to parse magnet URI: ${error.message}`);
        }
    }

    /**
     * Start the RtcTorrent client
     */
    async start() {
        this.webRtcManager = new WebRTCManager(this.options);
        this.announcer = new Announcer(this.options);

        console.log('RtcTorrent client started');
    }

    /**
     * Stop the RtcTorrent client
     */
    async stop() {
        // Close all connections
        for (const [_, torrent] of this.torrents) {
            await torrent.stop();
        }

        // Close WebRTC connections
        if (this.webRtcManager) {
            await this.webRtcManager.close();
        }

        console.log('RtcTorrent client stopped');
    }

    /**
     * Stream a video file from a torrent to a video element
     */
    async streamVideo(infoHash, fileIndex = 0, videoElement) {
        const torrent = this.torrents.get(infoHash);
        if (!torrent) {
            throw new Error(`Torrent with infoHash ${infoHash} not found`);
        }

        return await torrent.streamVideo(fileIndex, videoElement);
    }
}

/**
 * Torrent class representing a single torrent download
 */
class Torrent {
    constructor(client, torrentData, options) {
        this.client = client;
        this.data = torrentData;
        this.options = options;
        this.peers = new Map();
        this.pieces = new Map(); // Store downloaded pieces
        this.downloaded = 0;
        this.uploaded = 0;
        this.active = false;
        this.signalChannel = null;
        this.pieceLength = torrentData.info?.piece_length || 256 * 1024;
        this.totalSize = this.calculateTotalSize(torrentData);
        this.files = this.extractFiles(torrentData);
        this.pieceCount = Math.ceil(this.totalSize / this.pieceLength);

        // For video streaming
        this.mediaSource = null;
        this.sourceBuffer = null;
    }

    /**
     * Calculate total size from torrent data
     */
    calculateTotalSize(torrentData) {
        if (torrentData.info?.length) {
            return torrentData.info.length;
        }

        if (torrentData.info?.files && Array.isArray(torrentData.info?.files)) {
            return torrentData.info.files.reduce((sum, file) => sum + (file.length || 0), 0);
        }

        return 0;
    }

    /**
     * Extract file information from torrent data
     */
    extractFiles(torrentData) {
        if (torrentData.info?.length && torrentData.info?.name) {
            return [{
                name: torrentData.info.name,
                length: torrentData.info.length,
                offset: 0
            }];
        }

        if (torrentData.info?.files && Array.isArray(torrentData.info.files)) {
            let offset = 0;
            return torrentData.info.files.map(file => {
                const fileInfo = {
                    name: Array.isArray(file.path) ? file.path.join('/') : file.path,
                    length: file.length,
                    offset: offset
                };
                offset += file.length;
                return fileInfo;
            });
        }

        return [];
    }

    /**
     * Start downloading the torrent
     */
    async start() {
        this.active = true;

        // Initialize signal channel for WebRTC
        this.signalChannel = new SignalChannel(this.client.options.trackerUrl, this.data.infoHash);

        // Listen for incoming WebRTC offers from tracker
        this.signalChannel.on('offer', (sdpOffer) => {
            this.handleOffer(sdpOffer);
        });

        // Listen for WebRTC answers
        this.signalChannel.on('answer', (sdpAnswer) => {
            this.handleAnswer(sdpAnswer);
        });

        // Start announcing to tracker
        this.announceLoop();

        console.log(`Started torrent ${this.data.infoHash}`);

        return this;
    }

    /**
     * Start seeding the torrent (announce as having all pieces)
     */
    async seed() {
        this.isSeeder = true;

        // If we have original file data, we can serve pieces to other peers
        if (this.data.torrent && this.data.torrent._originalFiles) {
            // Calculate total size from original files
            let totalFileSize = 0;
            for (const fileBuffer of this.data.torrent._originalFiles) {
                totalFileSize += fileBuffer.length;
            }

            this.downloaded = totalFileSize;
            this.totalSize = totalFileSize;

            console.log(`Seeding torrent with ${this.data.torrent._originalFiles.length} file(s), total size: ${totalFileSize} bytes`);
        }

        return await this.start();
    }

    /**
     * Stop downloading the torrent
     */
    async stop() {
        this.active = false;

        // Close all peer connections
        for (const [_, peer] of this.peers) {
            await peer.close();
        }

        if (this.signalChannel) {
            this.signalChannel.close();
        }

        console.log(`Stopped torrent ${this.data.infoHash}`);
    }

    /**
     * Main announce loop to get peers from tracker
     */
    async announceLoop() {
        if (!this.active) return;

        try {
            // WebRTC announce to get WebRTC peers and send/receive SDP
            const rtcResponse = await this.announce({
                rtctorrent: 1,
                rtcoffer: this.getPendingOffer(),
                rtcrequest: 1,
                event: 'started',
                numwant: 50
            }, true);

            // Process RTC interval if provided by tracker
            if (rtcResponse && rtcResponse.rtc_interval) {
                this.client.options.rtcInterval = rtcResponse.rtc_interval;
            }

            // Process WebRTC peers
            if (rtcResponse && rtcResponse.rtc_peers) {
                for (const peer of rtcResponse.rtc_peers) {
                    await this.connectToWebRTCPeer(peer);
                }
            }

        } catch (error) {
            console.error('RtcTorrent announce error:', error);
        } finally {
            if (this.active) {
                // Schedule next announce
                setTimeout(() => this.announceLoop(), this.client.options.rtcInterval);
            }
        }
    }

    /**
     * Announce to tracker
     */
    async announce(params, isRtc = false) {
        const url = new URL(this.client.options.trackerUrl);

        // Add standard BitTorrent parameters
        const infoHashBuffer = this.hexToUint8Array(this.data.infoHash);
        url.searchParams.set('info_hash', this.urlEncodeInfoHash(infoHashBuffer));
        url.searchParams.set('peer_id', this.generatePeerId());
        url.searchParams.set('port', 6881); // Mock port
        url.searchParams.set('uploaded', this.uploaded.toString());
        url.searchParams.set('downloaded', this.downloaded.toString());
        url.searchParams.set('left', (this.totalSize - this.downloaded).toString());
        url.searchParams.set('compact', '1');
        url.searchParams.set('no_peer_id', '1');

        // Add WebRTC parameters if requested
        if (isRtc) {
            url.searchParams.set('rtctorrent', '1');
            if (params.rtcoffer) {
                url.searchParams.set('rtcoffer', encodeURIComponent(params.rtcoffer));
            }
            if (params.rtcrequest) {
                url.searchParams.set('rtcrequest', '1');
            }
        }

        // Add other parameters
        for (const [key, value] of Object.entries(params)) {
            if (['event', 'numwant'].includes(key) && value !== undefined) {
                url.searchParams.set(key, value.toString());
            }
        }

        try {
            const response = await fetch(url.toString());
            if (!response.ok) {
                throw new Error(`Tracker responded with status: ${response.status}`);
            }

            // Parse the response (raw binary response for bencoded data)
            const buffer = await response.arrayBuffer();
            return this.parseBencodedResponse(new Uint8Array(buffer));
        } catch (error) {
            console.error('Announce request failed:', error);
            throw error;
        }
    }

    /**
     * URL encode info_hash properly (20 bytes, specially handled by trackers)
     */
    urlEncodeInfoHash(uint8Array) {
        let result = '';
        for (let i = 0; i < uint8Array.length; i++) {
            result += '%' + uint8Array[i].toString(16).padStart(2, '0');
        }
        return result;
    }

    /**
     * Convert hex string to Uint8Array
     */
    hexToUint8Array(hex) {
        const bytes = new Uint8Array(hex.length / 2);
        for (let i = 0; i < bytes.length; i++) {
            bytes[i] = parseInt(hex.substr(i * 2, 2), 16);
        }
        return bytes;
    }

    /**
     * Connect to a WebRTC peer
     */
    async connectToWebRTCPeer(peerInfo) {
        try {
            const peerConnection = this.client.webRtcManager.createConnection();

            // Set up data channel for torrent communication
            const dataChannel = peerConnection.createDataChannel('torrent-data', {
                ordered: false,
                maxRetransmits: 3
            });

            this.setupDataChannel(dataChannel, peerInfo);

            // Handle ICE candidates
            peerConnection.onicecandidate = (event) => {
                if (event.candidate) {
                    // Send ICE candidate to remote peer via signaling channel
                    this.signalChannel.sendICECandidate(event.candidate, peerInfo.id);
                }
            };

            // Handle incoming data channels
            peerConnection.ondatachannel = (event) => {
                this.setupDataChannel(event.channel, peerInfo);
            };

            // If this is a new connection and we have data to share, create an offer
            if (!peerInfo.hasOffer) {
                const offer = await peerConnection.createOffer({
                    offerToReceiveAudio: false,
                    offerToReceiveVideo: false
                });

                await peerConnection.setLocalDescription(offer);

                // Send offer to remote peer via tracker
                this.signalChannel.sendOffer(offer.sdp, peerInfo.id);
            }

            // Store the connection
            const connectionId = peerInfo.id || `conn_${Date.now()}_${Math.random()}`;
            this.peers.set(connectionId, {
                connection: peerConnection,
                channel: dataChannel,
                info: peerInfo,
                connected: false
            });

        } catch (error) {
            console.error('Error connecting to WebRTC peer:', error);
        }
    }

    /**
     * Set up data channel for torrent communication
     */
    setupDataChannel(channel, peerInfo) {
        channel.onopen = () => {
            console.log('WebRTC data channel opened for peer:', peerInfo?.id);
            if (peerInfo && this.peers.has(peerInfo.id)) {
                this.peers.get(peerInfo.id).connected = true;
            }
        };

        channel.onclose = () => {
            console.log('WebRTC data channel closed for peer:', peerInfo?.id);
        };

        channel.onerror = (error) => {
            console.error('WebRTC data channel error:', error);
        };

        channel.onmessage = (event) => {
            // Handle incoming torrent data/pieces
            this.handleMessage(event.data, peerInfo);
        };
    }

    /**
     * Handle received message
     */
    handleMessage(data, peerInfo) {
        try {
            // Handle different types of messages
            if (typeof data === 'string') {
                try {
                    const parsed = JSON.parse(data);

                    // Handle control messages
                    if (parsed.type) {
                        switch (parsed.type) {
                            case 'piece_request':
                                this.handlePieceRequest(parsed.pieceIndex, peerInfo);
                                break;
                            case 'piece_data':
                                this.handlePieceData(parsed.pieceIndex, parsed.data, peerInfo);
                                break;
                            default:
                                console.log('Unknown message type:', parsed.type);
                        }
                    }
                } catch (e) {
                    // Not JSON, probably raw piece data
                    console.log('Received raw data from peer');
                }
            } else if (data instanceof ArrayBuffer) {
                // Raw piece data
                this.processPieceData(new Uint8Array(data), peerInfo);
            }
        } catch (error) {
            console.error('Error handling message:', error);
        }
    }

    /**
     * Handle piece request from a peer
     */
    handlePieceRequest(pieceIndex, peerInfo) {
        // Check if we have the original file data for this torrent
        if (this.data.torrent && this.data.torrent._originalFiles && this.data.torrent._pieceLength) {
            // Get the piece data from the original files
            const pieceLength = this.data.torrent._pieceLength;
            const offset = pieceIndex * pieceLength;

            // Combine all original files into a single buffer to get the piece
            let combinedBuffer;
            if (this.data.torrent._originalFiles && this.data.torrent._originalFiles.length > 0) {
                combinedBuffer = Buffer.concat(this.data.torrent._originalFiles);

                // Extract the requested piece
                const start = offset;
                const end = Math.min(offset + pieceLength, combinedBuffer.length);
                const pieceData = combinedBuffer.slice(start, end);

                // Send the piece data back to the requesting peer
                if (peerInfo && this.peers.has(peerInfo.id || Object.keys(this.peers)[0])) {
                    const peer = this.peers.get(peerInfo.id || Object.keys(this.peers)[0]);
                    if (peer.channel && peer.channel.readyState === 'open') {
                        const message = {
                            type: 'piece_data',
                            pieceIndex: pieceIndex,
                            data: pieceData
                        };

                        peer.channel.send(JSON.stringify(message));
                        console.log(`Sent piece ${pieceIndex} to peer`);
                    }
                }

                return;
            }
        }

        // In a real implementation, we would send the piece if we have it
        // For now, we'll just log it
        console.log(`Peer requested piece ${pieceIndex}, but we don't have the file data`);
    }

    /**
     * Handle incoming piece data
     */
    handlePieceData(pieceIndex, pieceData, peerInfo) {
        // Store the piece
        this.pieces.set(pieceIndex, pieceData);
        this.downloaded += pieceData.length;

        console.log(`Received piece ${pieceIndex}, total downloaded: ${this.downloaded}/${this.totalSize}`);

        // Update torrent progress
        this.updateProgress();
    }

    /**
     * Process raw piece data
     */
    processPieceData(pieceData, peerInfo) {
        // Raw data handling - would normally have protocol framing
        console.log(`Received ${pieceData.length} bytes from peer`);
    }

    /**
     * Handle incoming SDP offer
     */
    async handleOffer(sdpOffer) {
        const peerConnection = this.client.webRtcManager.createConnection();

        // Set up data channel
        peerConnection.ondatachannel = (event) => {
            this.setupDataChannel(event.channel);
        };

        try {
            // Set remote description
            await peerConnection.setRemoteDescription({ type: 'offer', sdp: sdpOffer });

            // Create answer
            const answer = await peerConnection.createAnswer();
            await peerConnection.setLocalDescription(answer);

            // Send answer back to remote peer via signaling
            this.signalChannel.sendAnswer(answer.sdp);

            // Store connection
            const connectionId = `incoming_${Date.now()}`;
            this.peers.set(connectionId, {
                connection: peerConnection,
                info: { source: 'incoming' },
                connected: false
            });

        } catch (error) {
            console.error('Error handling offer:', error);
        }
    }

    /**
     * Handle incoming SDP answer
     */
    async handleAnswer(sdpAnswer) {
        // Find a connection that's waiting for an answer
        for (const [id, peer] of this.peers) {
            if (!peer.connected && peer.connection.signalingState === 'have-local-offer') {
                try {
                    await peer.connection.setRemoteDescription({ type: 'answer', sdp: sdpAnswer });
                    peer.connected = true;
                    console.log('WebRTC connection established with peer');
                    break;
                } catch (error) {
                    console.error('Error setting remote answer:', error);
                }
            }
        }
    }

    /**
     * Get pending offer to send
     */
    getPendingOffer() {
        // For now, return null - in a real implementation we'd manage pending offers
        return null;
    }

    /**
     * Generate a random peer ID
     */
    generatePeerId() {
        let peerId = '-RT1000-'; // RtcTorrent client identifier
        for (let i = 0; i < 12; i++) {
            peerId += Math.floor(Math.random() * 10).toString();
        }
        return peerId;
    }

    /**
     * Parse bencoded response from tracker
     */
    parseBencodedResponse(responseBytes) {
        // This is a very basic bencode parser for demonstration
        // In a real implementation, use a proper bencode library
        try {
            // Look for common response keys
            const responseText = new TextDecoder().decode(responseBytes);

            // This is a simplified extraction - in reality you'd properly parse bencoded data
            const result = {};

            // Extract interval if present
            if (responseText.includes('interval')) {
                // Find the interval value in the bencoded response
                const intervalMatch = responseText.match(/interval.i(\d+)/);
                if (intervalMatch) {
                    result.interval = parseInt(intervalMatch[1]);
                }
            }

            // Extract rtc_interval if present
            if (responseText.includes('rtc interval')) {
                const rtcIntervalMatch = responseText.match(/rtc interval.i(\d+)/);
                if (rtcIntervalMatch) {
                    result.rtc_interval = parseInt(rtcIntervalMatch[1]) * 1000; // Convert to milliseconds
                }
            }

            return result;
        } catch (e) {
            console.error('Error parsing bencoded response:', e);
            return {};
        }
    }

    /**
     * Update torrent download progress
     */
    updateProgress() {
        const progress = (this.downloaded / this.totalSize) * 100;
        console.log(`Torrent progress: ${progress.toFixed(2)}% (${this.downloaded}/${this.totalSize})`);
    }

    /**
     * Stream a video file to a video element
     */
    async streamVideo(fileIndex = 0, videoElement) {
        if (!videoElement || !(videoElement instanceof HTMLVideoElement || videoElement.tagName === 'VIDEO')) {
            throw new Error('Invalid video element provided');
        }

        const file = this.files[fileIndex];
        if (!file) {
            throw new Error(`File at index ${fileIndex} not found`);
        }

        // Create MediaSource for streaming
        if (!window.MediaSource) {
            throw new Error('MediaSource API not supported in this browser');
        }

        this.mediaSource = new MediaSource();
        videoElement.src = URL.createObjectURL(this.mediaSource);

        // Wait for the MediaSource to be open
        return new Promise((resolve, reject) => {
            this.mediaSource.addEventListener('sourceopen', async () => {
                try {
                    // Create source buffer for video
                    // We'll assume mp4/video/mp4 for this example
                    // In a real implementation, detect the file type
                    this.sourceBuffer = this.mediaSource.addSourceBuffer('video/mp4');

                    // Start downloading and appending pieces to the source buffer
                    await this.startVideoStreaming(file, this.sourceBuffer);

                    resolve(this.sourceBuffer);
                } catch (error) {
                    reject(error);
                }
            });
        });
    }

    /**
     * Start streaming video data to source buffer
     */
    async startVideoStreaming(file, sourceBuffer) {
        // This is a simplified streaming implementation
        // In a real implementation, we would:
        // 1. Download pieces in order
        // 2. Append them to the source buffer as they arrive
        // 3. Handle buffering and playback appropriately

        let offset = file.offset;
        let bytesAppended = 0;

        sourceBuffer.addEventListener('updateend', () => {
            if (this.downloaded < this.totalSize && !sourceBuffer.updating) {
                // Continue appending more data when buffer is ready
                this.appendNextChunk(sourceBuffer, offset, bytesAppended);
            }
        });

        // Start the initial chunk
        this.appendNextChunk(sourceBuffer, offset, bytesAppended);
    }

    /**
     * Append next chunk of data to source buffer
     */
    async appendNextChunk(sourceBuffer, offset, bytesAppended) {
        // Find the next piece that corresponds to our offset
        const pieceIndex = Math.floor(offset / this.pieceLength);
        const pieceOffsetInPiece = offset % this.pieceLength;

        // Wait for the piece to be downloaded
        while (!this.pieces.has(pieceIndex) && this.downloaded < this.totalSize) {
            // In a real implementation, we'd request this piece from peers
            // For now, we'll just wait a bit and check again
            await new Promise(resolve => setTimeout(resolve, 100));
        }

        if (this.pieces.has(pieceIndex)) {
            const pieceData = this.pieces.get(pieceIndex);
            const startInPiece = pieceOffsetInPiece;
            const endInPiece = Math.min(startInPiece + 64 * 1024, pieceData.length); // Read 64KB chunks

            if (startInPiece < pieceData.length) {
                const chunk = pieceData.slice(startInPiece, endInPiece);

                if (!sourceBuffer.updating) {
                    sourceBuffer.appendBuffer(chunk.buffer.slice(chunk.byteOffset, chunk.byteOffset + chunk.byteLength));
                    bytesAppended += chunk.length;
                }
            }
        }
    }
}

/**
 * Signal channel for WebRTC negotiation via HTTP tracker
 */
class SignalChannel extends EventTarget {
    constructor(trackerUrl, infoHash) {
        super();
        this.trackerUrl = trackerUrl;
        this.infoHash = infoHash;
        this.wsConnection = null; // Could use WebSocket for real-time signaling
        this.messageQueue = []; // Queue for messages while connecting
        this.peerConnections = new Map();
    }

    /**
     * Send an offer to the remote peer via tracker
     */
    async sendOffer(sdpOffer, peerId) {
        try {
            // Send via HTTP tracker using rtcoffer parameter
            const params = new URLSearchParams({
                info_hash: this.hexToBinary(this.infoHash),
                peer_id: this.generatePeerId(),
                rtcoffer: encodeURIComponent(sdpOffer),
                rtctorrent: '1',
                event: 'started'
            });

            const response = await fetch(`${this.trackerUrl}?${params}`, {
                method: 'GET',
                headers: {
                    'Content-Type': 'application/x-www-form-urlencoded',
                }
            });

            if (!response.ok) {
                throw new Error(`Tracker responded with status: ${response.status}`);
            }

            console.log('Offer sent successfully via tracker');
        } catch (error) {
            console.error('Error sending offer:', error);
        }
    }

    /**
     * Send an answer to the remote peer via tracker
     */
    async sendAnswer(sdpAnswer) {
        try {
            const params = new URLSearchParams({
                info_hash: this.hexToBinary(this.infoHash),
                peer_id: this.generatePeerId(),
                rtcoffer: encodeURIComponent(sdpAnswer), // Using same param for answer
                rtctorrent: '1',
                event: 'started'
            });

            const response = await fetch(`${this.trackerUrl}?${params}`, {
                method: 'GET'
            });

            if (!response.ok) {
                throw new Error(`Tracker responded with status: ${response.status}`);
            }

            console.log('Answer sent successfully via tracker');
        } catch (error) {
            console.error('Error sending answer:', error);
        }
    }

    /**
     * Send ICE candidate to tracker
     */
    async sendICECandidate(candidate, peerId) {
        // Send ICE candidate via HTTP tracker
        // This would be handled differently in a production system
        try {
            const params = new URLSearchParams({
                info_hash: this.hexToBinary(this.infoHash),
                peer_id: this.generatePeerId(),
                ice_candidate: encodeURIComponent(JSON.stringify(candidate)),
                rtctorrent: '1'
            });

            await fetch(`${this.trackerUrl}?${params}`, {
                method: 'GET'
            });

            console.log('ICE candidate sent');
        } catch (error) {
            console.error('Error sending ICE candidate:', error);
        }
    }

    /**
     * Convert hex string to binary format for info_hash
     */
    hexToBinary(hex) {
        const bytes = new Uint8Array(hex.length / 2);
        for (let i = 0; i < bytes.length; i++) {
            bytes[i] = parseInt(hex.substr(i * 2, 2), 16);
        }

        // Convert to percent-encoded string for URL
        let result = '';
        for (let i = 0; i < bytes.length; i++) {
            result += '%' + bytes[i].toString(16).padStart(2, '0');
        }
        return result;
    }

    /**
     * Generate a random peer ID
     */
    generatePeerId() {
        let peerId = '-RT1000-';
        for (let i = 0; i < 12; i++) {
            peerId += Math.floor(Math.random() * 10).toString();
        }
        return encodeURIComponent(peerId);
    }

    /**
     * Close the signal channel
     */
    close() {
        if (this.wsConnection) {
            this.wsConnection.close();
        }
        this.peerConnections.clear();
    }

    /**
     * Emit a custom event
     */
    emit(eventName, data) {
        const event = new CustomEvent(eventName, { detail: data });
        this.dispatchEvent(event);
    }

    /**
     * Add event listener
     */
    on(eventName, callback) {
        this.addEventListener(eventName, (event) => callback(event.detail));
    }
}

/**
 * WebRTC manager for handling connections
 */
class WebRTCManager {
    constructor(options) {
        this.options = options;
        this.connections = new Map();
        this.nextId = 0;
    }

    /**
     * Create a new WebRTC connection
     */
    createConnection(config = {}) {
        const rtcConfig = {
            iceServers: this.options.iceServers || [
                { urls: 'stun:stun.l.google.com:19302' }
            ],
            ...config
        };

        const connection = new RTCPeerConnection(rtcConfig);
        const connectionId = `conn_${this.nextId++}`;

        this.connections.set(connectionId, connection);

        // Clean up closed connections
        connection.onconnectionstatechange = () => {
            if (connection.connectionState === 'closed' || connection.connectionState === 'failed') {
                this.connections.delete(connectionId);
            }
        };

        return connection;
    }

    /**
     * Close all connections
     */
    async close() {
        for (const [_, connection] of this.connections) {
            connection.close();
        }
        this.connections.clear();
    }
}

